// Java 25 exam prep - Checked numeric conversions
// Learn: widen before int math wraps; Math.*Exact turns overflow into errors.
static long scaleBytes(int megabytes) {
  // Widen first: the int product 4_096 * 1_048_576 would wrap to 0.
  return (long) megabytes * 1_048_576;
}

static int toCheckedInt(long value) {
  // toIntExact throws ArithmeticException instead of truncating bits.
  return Math.toIntExact(value);
}

long total = Math.multiplyExact(scaleBytes(4_096), 4L);
System.out.println(toCheckedInt(total / 1_048_576));
